"use client";
import { useState } from "react";
import { Trash2 } from "lucide-react";
import Footer from "./footer";

export default function FavoriteListPage() {
    const [favorites, setFavorites] = useState([
        {
            id: 1,
            name: "Be Nice Shower Cream, Perfect Elastic Formula, 450 ml.",
            price: 109,
            image: "/images/products/showercream.png",
            inStock: true,
        },
        {
            id: 2,
            name: "Protex Lavender Ice Freeze Soap Bar 60 g.",
            price: 57,
            image: "/images/products/protex.png",
            inStock: false,
        },
        {
            id: 3,
            name: "KFC BamBam BOX Menu TheBox special",
            price: 159,
            image: "/images/products/kfc.png",
            inStock: true,
        },
    ]);

    const removeFavorite = (id) => {
        setFavorites(prev => prev.filter(item => item.id !== id));
    };

    const addToCart = (item) => {
        alert(`${item.name} added to cart!`);
    };

    return (
        <div className="min-h-screen bg-gray-50 font-sans">
            {/* Breadcrumb */}
            <div className="max-w-7xl mx-auto px-6 py-4 text-sm text-gray-500">
                Home / My Favorite List
            </div>

            {/* Title */}
            <div className="max-w-7xl mx-auto px-6 mb-6">
                <h1 className="text-2xl font-semibold">My Favorite List</h1>
                <p className="text-gray-500 mt-1">
                    There are {favorites.length} product{favorites.length > 1 ? "s" : ""} in my favorite list.
                </p>
            </div>

            {/* Table */}
            <div className="max-w-7xl mx-auto px-6">
                <div className="overflow-x-auto bg-white shadow rounded-lg">
                    <table className="min-w-full divide-y divide-gray-200">
                        <thead className="bg-gray-200">
                        <tr>
                            <th className="px-4 py-2 text-left text-sm font-medium text-gray-700">Product</th>
                            <th className="px-4 py-2 text-left text-sm font-medium text-gray-700">Amount</th>
                            <th className="px-4 py-2 text-left text-sm font-medium text-gray-700">Status</th>
                            <th className="px-4 py-2 text-left text-sm font-medium text-gray-700">Actions</th>
                        </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-200">
                        {favorites.map(item => (
                            <tr key={item.id}>
                                <td className="px-4 py-3 flex items-center space-x-3">
                                    <input type="checkbox" className="h-4 w-4 text-green-600" />
                                    <img src={item.image} alt={item.name} className="w-12 h-12 object-contain" />
                                    <span className="text-sm font-medium">{item.name}</span>
                                </td>
                                <td className="px-4 py-3 text-sm">${item.price.toFixed(2)}</td>
                                <td className="px-4 py-3">
                                    {item.inStock ? (
                                        <span className="px-2 py-1 text-xs font-medium text-white bg-green-600 rounded-full">In stock</span>
                                    ) : (
                                        <span className="px-2 py-1 text-xs font-medium text-white bg-red-600 rounded-full">Out of stock</span>
                                    )}
                                </td>
                                <td className="px-4 py-3 flex items-center space-x-2">
                                    {item.inStock ? (
                                        <button
                                            onClick={() => addToCart(item)}
                                            className="px-3 py-1 bg-green-600 text-white text-xs rounded hover:bg-green-700"
                                        >
                                            Add to cart
                                        </button>
                                    ) : (
                                        <button className="px-3 py-1 bg-black text-white text-xs rounded cursor-not-allowed">
                                            Contact us
                                        </button>
                                    )}
                                    <button onClick={() => removeFavorite(item.id)} className="text-red-500">
                                        <Trash2 size={16} />
                                    </button>
                                </td>
                            </tr>
                        ))}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* Footer */}
            <Footer />


        </div>
    );
}
